"""
report_generator.py
-------------------

A tiny but flexible HTML‑report generator built on Jinja2.

Features
~~~~~~~~
* Base template with header/footer and CSS.
* Template inheritance – create new report types by extending ``base.html``.
* Render tables from ``list[dict]`` data structures.
* Conditional row highlighting based on numeric thresholds.
* Easy to plug in your own templates (filesystem or dict loader).

Example
~~~~~~~
>>> from report_generator import ReportRenderer
>>> data = [
...     {"name": "Alice", "score": 92, "age": 30},
...     {"name": "Bob",   "score": 67, "age": 24},
...     {"name": "Cathy", "score": 78, "age": 28},
... ]
>>> thresholds = {"score": 80}          # highlight rows where score > 80
>>> renderer = ReportRenderer()
>>> html = renderer.render(
...     "simple_report.html",
...     data=data,
...     highlight_rules=thresholds,
...     title="Demo Report",
... )
>>> # ``html`` now contains a full HTML document.
"""

from __future__ import annotations

import datetime
import pathlib
from typing import Any, Dict, Iterable, List, Mapping, Optional

from jinja2 import Environment, FileSystemLoader, DictLoader, select_autoescape


# --------------------------------------------------------------------------- #
# Default templates (kept in a dict so the module works without any external
# files).  You can replace or extend them by passing a ``template_dir`` to
# ``ReportRenderer`` or by calling ``add_template``.
# --------------------------------------------------------------------------- #
DEFAULT_TEMPLATES: Dict[str, str] = {
    # ----------------------------------------------------------------------- #
    # Base template – defines the overall page skeleton, CSS and three blocks:
    #   * title   – <title> element
    #   * header  – page header
    #   * content – main body (usually a table)
    #   * footer  – page footer
    # ----------------------------------------------------------------------- #
    "base.html": """
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>{% block title %}Report{% endblock %}</title>
    <style>
        body {font-family: Arial, Helvetica, sans-serif; margin:0; padding:0;}
        header, footer {
            background: #333;
            color: #fff;
            padding: 1rem;
            text-align: center;
        }
        .content {padding: 1rem;}
        table {
            width: 100%;
            border-collapse: collapse;
            margin-top: 1rem;
        }
        th, td {
            border: 1px solid #ddd;
            padding: 0.5rem;
            text-align: left;
        }
        th {background: #f2f2f2;}
        tr.highlight {background: #ffdddd;}
    </style>
</head>
<body>
    <header>{% block header %}Header{% endblock %}</header>
    <div class="content">
        {% block content %}{% endblock %}
    </div>
    <footer>{% block footer %}Footer{% endblock %}</footer>
</body>
</html>
""",
    # ----------------------------------------------------------------------- #
    # Simple report – extends the base template and renders a generic table.
    # The template expects:
    #   * data – list of dicts (rows)
    #   * columns – ordered list of column names
    #   * generation_time – string with the timestamp
    #   * any additional context you want to expose.
    # ----------------------------------------------------------------------- #
    "simple_report.html": """
{% extends "base.html" %}

{% block title %}{{ title | default('Simple Report') }}{% endblock %}

{% block header %}
    {{ header | default('Simple Data Report') }}
{% endblock %}

{% block content %}
    <h2>{{ subtitle | default('Data Overview') }}</h2>

    {% if data %}
        <table>
            <thead>
                <tr>
                    {% for col in columns %}
                        <th>{{ col | capitalize }}</th>
                    {% endfor %}
                </tr>
            </thead>
            <tbody>
                {% for row in data %}
                    <tr{% if row._highlight %} class="highlight"{% endif %}>
                        {% for col in columns %}
                            <td>{{ row[col] }}</td>
                        {% endfor %}
                    </tr>
                {% endfor %}
            </tbody>
        </table>
    {% else %}
        <p>No data to display.</p>
    {% endif %}
{% endblock %}

{% block footer %}
    {{ footer | default('Generated on') }} {{ generation_time }}
{% endblock %}
""",
    # ----------------------------------------------------------------------- #
    # Example of a more specialized report – you can add as many as you like.
    # This one adds a summary section above the table.
    # ----------------------------------------------------------------------- #
    "detailed_report.html": """
{% extends "base.html" %}

{% block title %}{{ title | default('Detailed Report') }}{% endblock %}

{% block header %}
    {{ header | default('Detailed Data Report') }}
{% endblock %}

{% block content %}
    <h2>{{ subtitle | default('Data Summary') }}</h2>

    {% if summary %}
        <ul>
            {% for key, value in summary.items() %}
                <li><strong>{{ key }}:</strong> {{ value }}</li>
            {% endfor %}
        </ul>
    {% endif %}

    {% if data %}
        <h3>Data Table</h3>
