# --------------------------------------------------------------------------- #
# Helper functions
# --------------------------------------------------------------------------- #
def _extract_columns(data: Iterable[Mapping[str, Any]]) -> List[str]:
    """
    Return an ordered list of column names appearing in ``data``.
    The order is alphabetical for reproducibility.
    """
    cols = set()
    for row in data:
        cols.update(row.keys())
    # Remove any internal keys that start with '_' (e.g. _highlight)
    cols = {c for c in cols if not c.startswith("_")}
    return sorted(cols)


def _apply_highlight_rules(
    data: List[Dict[str, Any]],
    highlight_rules: Optional[Mapping[str, float]],
) -> List[Dict[str, Any]]:
    """
    Mutates each row in ``data`` by adding a boolean ``_highlight`` key.
    ``_highlight`` is ``True`` if **any** of the supplied ``highlight_rules``
    are satisfied for that row.

    ``highlight_rules`` maps a column name to a numeric threshold.
    Rows where ``row[col]`` > ``threshold`` (and the value is numeric) are
    marked for highlighting.
    """
    if not highlight_rules:
        # No rules – ensure the flag exists and is False for all rows.
        for row in data:
            row["_highlight"] = False
        return data

    for row in data:
        highlight = False
        for col, threshold in highlight_rules.items():
            val = row.get(col)
            # Only numeric values make sense for > comparisons.
            if isinstance(val, (int, float)):
                if val > threshold:
                    highlight = True
                    break
        row["_highlight"] = highlight
    return data


